3901       // Collect the minimum number of sign bits that are shared by every vector
3902       // element referenced by the shuffle.
3903       auto *Shuf = dyn_cast<ShuffleVectorInst>(U);
3904       if (!Shuf) {
3905         // FIXME: Add support for shufflevector constant expressions.
3906         return 1;
3907       }
3908       APInt DemandedLHS, DemandedRHS;
3909       // For undef elements, we don't know anything about the common state of
3910       // the shuffle result.
3911       if (!getShuffleDemandedElts(Shuf, DemandedElts, DemandedLHS, DemandedRHS))
3912         return 1;
3913       Tmp = std::numeric_limits<unsigned>::max();
3914       if (!!DemandedLHS) {
3915         const Value *LHS = Shuf->getOperand(0);
3916         Tmp = ComputeNumSignBits(LHS, DemandedLHS, Depth + 1, Q);
3917       }
3918       // If we don't know anything, early out and try computeKnownBits
3919       // fall-back.
3920       if (Tmp == 1)
3921         break;
3922       if (!!DemandedRHS) {
3923         const Value *RHS = Shuf->getOperand(1);
3924         Tmp2 = ComputeNumSignBits(RHS, DemandedRHS, Depth + 1, Q);
3925         Tmp = std::min(Tmp, Tmp2);
3926       }
3927       // If we don't know anything, early out and try computeKnownBits
3928       // fall-back.
3929       if (Tmp == 1)
3930         break;
3931       assert(Tmp <= TyBits && "Failed to determine minimum sign bits");
3932       return Tmp;
3933     }
3934     case Instruction::Call: {
3935       if (const auto *II = dyn_cast<IntrinsicInst>(U)) {
3936         switch (II->getIntrinsicID()) {
3937         default: break;
3938         case Intrinsic::abs:
3939           Tmp = ComputeNumSignBits(U->getOperand(0), Depth + 1, Q);
3940           if (Tmp == 1) break;
3941 
3942           // Absolute value reduces number of sign bits by at most 1.
3943           return Tmp - 1;
3944         case Intrinsic::smin:
3945         case Intrinsic::smax: {
3946           const APInt *CLow, *CHigh;
3947           if (isSignedMinMaxIntrinsicClamp(II, CLow, CHigh))
3948             return std::min(CLow->getNumSignBits(), CHigh->getNumSignBits());
3949         }
3950         }
3951       }
3952     }
3953     }
3954   }
3955 
3956   // Finally, if we can prove that the top bits of the result are 0's or 1's,
3957   // use this information.
3958 
3959   // If we can examine all elements of a vector constant successfully, we're
3960   // done (we can't do any better than that). If not, keep trying.
3961   if (unsigned VecSignBits =
3962           computeNumSignBitsVectorConstant(V, DemandedElts, TyBits))
3963     return VecSignBits;
3964 
3965   KnownBits Known(TyBits);
3966   computeKnownBits(V, DemandedElts, Known, Depth, Q);
3967 
3968   // If we know that the sign bit is either zero or one, determine the number of
3969   // identical bits in the top of the input value.
3970   return std::max(FirstAnswer, Known.countMinSignBits());
3971 }
